import { addSnackbar, submitIntercept, pageRefresh } from 'Common/Helpers.ts';
import { ajax, type AjaxJSONResponse } from 'Common/Ajax.ts';
import { AJAX_TIMEOUT, SNACKBAR_FAIL_LIFE } from 'Common/Constants.ts';
import { buttonToggle } from 'Common/Inputs.ts';

export class EditFFLinks {
  private readonly form: HTMLFormElement | null = null;
  private readonly button: HTMLInputElement | null = null;

  public constructor() {
    this.form = document.querySelector('#ff_link_user');
    if (this.form) {
      submitIntercept(this.form, this.link.bind(this));
      this.button = this.form.querySelector('#ff_link_submit');
    }
  }

  private link(): void {
    if (this.form && this.button) {
      //Get form data
      const form_data = new FormData(this.form);
      buttonToggle(this.button);
      void ajax(`${location.protocol}//${location.host}/api/uc/fflink`, form_data, 'json', 'POST', AJAX_TIMEOUT, true).then((response) => {
          const data = response as AjaxJSONResponse;
          if (data.data === true) {
            addSnackbar('Character linked successfully. Reloading page...', 'success');
            pageRefresh();
          } else {
            addSnackbar(data.reason, 'failure', SNACKBAR_FAIL_LIFE);
          }
          if (this.button) {
            buttonToggle(this.button);
          }
        });
    }
  }
}
